const response = JSON.parse($input.first().json.data).response;
const match = response.match(/\{[\s\S]*\}/);
if (match) {
  const scored = JSON.parse(match[0]);
  const lead = $('Webhook Trigger').first().json.body;
  return [{ json: { ...lead, ...scored, scored_at: new Date().toISOString() } }];
}
throw new Error('Failed to parse scoring response');
